import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation, useNavigate } from 'react-router-dom';
import PizzaMenu from './components/PizzaMenu';
import Cart from './components/Cart';
import CheckoutForm from './components/CheckoutForm';
import OrderSuccess from './components/OrderSuccess';
import AdminDashboard from './components/AdminDashboard';
import LoginPage from './components/LoginPage';
import VerificationScreen from './components/VerificationScreen';
import OrderHistory from './components/OrderHistory';
import OrderTracker from './components/OrderTracker';

const SHOW_NAV_PATHS = ['/', '/history', '/tracker', '/login'];

function BottomNav() {
  const { pathname } = useLocation();
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  if (!SHOW_NAV_PATHS.includes(pathname)) return null;

  const tabs = [
    { path: '/',        label: 'תפריט',   icon: '🍕' },
    { path: '/history', label: 'הזמנות',  icon: '📋' },
    { path: '/tracker', label: 'מעקב',    icon: '📍' },
    { path: '/login',   label: 'פרופיל',  icon: '👤' },
  ];

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex z-50"
      style={{ height: 64, boxShadow: '0 -4px 16px rgba(0,0,0,0.10)' }}
    >
      {tabs.map(tab => {
        const isActive = pathname === tab.path;
        return (
          <button
            key={tab.path}
            onClick={() => navigate(tab.path)}
            className="flex-1 flex flex-col items-center justify-center gap-0.5 transition-all"
            style={{
              border: 'none',
              background: 'none',
              color: isActive ? '#E31837' : '#9ca3af',
              cursor: 'pointer',
            }}
          >
            <span style={{ fontSize: 22, lineHeight: 1 }}>{tab.icon}</span>
            <span style={{ fontSize: 10, fontWeight: isActive ? 700 : 500, marginTop: 2 }}>
              {tab.label}
            </span>
            {isActive && (
              <span
                style={{
                  position: 'absolute',
                  bottom: 0,
                  width: 24,
                  height: 3,
                  background: '#E31837',
                  borderRadius: '3px 3px 0 0',
                }}
              />
            )}
          </button>
        );
      })}
    </nav>
  );
}

function AppContent() {
  return (
    <>
      <Routes>
        <Route path="/"        element={<PizzaMenu />} />
        <Route path="/cart"    element={<Cart />} />
        <Route path="/checkout" element={<CheckoutForm />} />
        <Route path="/success" element={<OrderSuccess />} />
        <Route path="/admin"   element={<AdminDashboard />} />
        <Route path="/login"   element={<LoginPage />} />
        <Route path="/verify"  element={<VerificationScreen />} />
        <Route path="/history" element={<OrderHistory />} />
        <Route path="/tracker" element={<OrderTracker />} />
      </Routes>
      <BottomNav />
    </>
  );
}

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
